    43	static rnti_t lcid_crnti_lookahead(uint8_t *pdu, int pdu_len)
    44	{
    45	  uint16_t mac_len = 0;
    46	  uint16_t mac_subheader_len = 0;
    47	  while (pdu_len >= 3) {
    48	    if ((pdu[0] & 0x3F) == UL_SCH_LCID_C_RNTI) {
    49	      // Extract C-RNTI value
    50	      rnti_t crnti = ((pdu[1] & 0xFF) << 8) | (pdu[2] & 0xFF);
    51	      LOG_D(NR_MAC, "Received a MAC CE for C-RNTI with %04x\n", crnti);
    52	      return crnti;
    53	    }
    54	    if (!get_mac_len(pdu, pdu_len, &mac_len, &mac_subheader_len)) {
    55	      break;
    56	    }
    57	    pdu += mac_len + mac_subheader_len;
    58	    pdu_len -= mac_len + mac_subheader_len;
    59	  }
    60	  return 0;
    61	}
