    63	int get_ul_tda(gNB_MAC_INST *nrmac, const NR_ServingCellConfigCommon_t *scc, int frame, int slot)
    64	{
    65	  /* we assume that this function is mutex-protected from outside */
    66	  NR_SCHED_ENSURE_LOCKED(&nrmac->sched_lock);
    67	
    68	  /* there is a mixed slot only when in TDD */
    69	  const NR_TDD_UL_DL_Pattern_t *tdd = scc->tdd_UL_DL_ConfigurationCommon ? &scc->tdd_UL_DL_ConfigurationCommon->pattern1 : NULL;
    70	  AssertFatal(tdd || nrmac->common_channels->frame_type == FDD, "Dynamic TDD not handled yet\n");
    71	
    72	  if (tdd && tdd->nrofUplinkSymbols > 1) { // if there is uplink symbols in mixed slot
    73	    const int nr_slots_period = tdd->nrofDownlinkSlots + tdd->nrofUplinkSlots + 1;
    74	    if ((slot % nr_slots_period) == tdd->nrofDownlinkSlots)
    75	      return 2;
    76	  }
    77	
    78	  // Avoid slots with the SRS
    79	  UE_iterator(nrmac->UE_info.list, UE) {
    80	    NR_sched_srs_t sched_srs = UE->UE_sched_ctrl.sched_srs;
    81	    if(sched_srs.srs_scheduled && sched_srs.frame == frame && sched_srs.slot == slot)
    82	      return 1;
    83	  }
    84	
    85	  return 0; // if FDD or not mixed slot in TDD, for now use default TDA (TODO handle CSI-RS slots)
    86	}
