   162	    int rep_idx = payload[m];
   163	    int estim_idx = overestim_bsr_index(rep_idx);
   164	    int idx = min(estim_idx, max);
   165	    estim_size += NR_LONG_BSR_TABLE[idx];
   166	
   167	    LOG_D(NR_MAC, "LONG BSR LCGID/m %d/%d Index %d estim index %d size %d", n, m, rep_idx, estim_idx, estim_size);
   168	    m++;
   169	  }
   170	  return estim_size;
